  1	import * as React from 'react';
  2	import {
  3	  CHART_LABELS,
  4	  Breakdown,
  5	  Metrics,
  6	  ServiceType,
  7	} from '@odf/ocs/constants';
  8	import { DATA_CONSUMPTION_QUERIES } from '@odf/ocs/queries';
  9	import { GraphEmpty } from '@odf/shared/charts';
 10	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 11	import { PrometheusResponse } from '@openshift-console/dynamic-plugin-sdk';
 12	import * as _ from 'lodash-es';
 13	import {
 14	  Chart,
 15	  ChartAxis,
 16	  ChartBar,
 17	  ChartGroup,
 18	  ChartLegend,
 19	  ChartThemeColor,
 20	  ChartTooltip,
 21	  ChartVoronoiContainer,
 22	} from '@patternfly/react-charts/victory';
 23	import {
 24	  getDataConsumptionChartData,
 25	  numberInWords,
 26	} from './data-consumption-card-utils';
 27	import './data-consumption-card.scss';
 28	
 29	type DataConsumptionGraphProps = {
 30	  prometheusResponse: PrometheusResponse[];
 31	  breakdownBy: string;
 32	  metric: Metrics;
 33	  loading: boolean;
 34	  loadError: boolean;
 35	};
 36	
 37	const DataConsumptionGraph: React.FC<DataConsumptionGraphProps> = ({
 38	  prometheusResponse: prometheusResults,
 39	  breakdownBy,
 40	  metric,
 41	  loading,
 42	  loadError,
 43	}) => {
 44	  const { t } = useCustomTranslation();
 45	
 46	  let padding: number;
 47	  let suffixLabel = '';
 48	  let maxVal: number;
 49	  let maxUnit: string;
 50	
 51	  const resultsWithKeys = (() => {
 52	    const queryMap =
 53	      DATA_CONSUMPTION_QUERIES[ServiceType.MCG][breakdownBy][metric] ??
 54	      DATA_CONSUMPTION_QUERIES[ServiceType.MCG][breakdownBy][Metrics.IOPS];
 55	    return Object.keys(queryMap).reduce((acc, curr, ind) => {
 56	      acc[curr] = prometheusResults[ind];
 57	      return acc;
 58	    }, {});
 59	  })();
 60	
 61	  const mcgBreakdown = breakdownBy === Breakdown.PROVIDERS ? 'type' : 'account';
 62	  const { chartData, legendData, max } = getDataConsumptionChartData(
 63	    resultsWithKeys,
 64	    mcgBreakdown,
 65	    metric,
 66	    t
 67	  );
 68	
 69	  const emptyData = chartData.some(_.isEmpty);
 70	
 71	  // chartData = [[],[],[],[],[],[]] or []
 72	  if (!loading && !loadError) {
 73	    padding =
 74	      chartData[0].length === 2 ||
 75	      (metric === Metrics.EGRESS && chartData.length === 2)
 76	        ? 125
 77	        : 25; // Adjusts spacing between each BarGroup
 78	    maxVal = max.value;
 79	    maxUnit = max.unit;
 80	    suffixLabel = maxUnit;
 81	    if (metric === Metrics.IOPS) {
 82	      suffixLabel = numberInWords(maxUnit, t);
 83	    }
 84	    // if suffixLabel is a non-empty string, show it in expected form
 85	    if (suffixLabel) suffixLabel = t('(in {{suffixLabel}})', { suffixLabel });
 86	  }
 87	
 88	  if (loadError || emptyData) {
 89	    return <GraphEmpty />;
 90	  }
 91	  if (!loading && !loadError) {
 92	    return (
 93	      <>
 94	        <div className="nb-data-consumption-card__chart-label text-secondary">
 95	          {`${CHART_LABELS(metric, t)} ${suffixLabel}`}
 96	        </div>
 97	        <Chart
 98	          ariaTitle={t('Data Consumption Graph')}
 99	          containerComponent={
100	            <ChartVoronoiContainer
101	              labelComponent={
102	                <ChartTooltip style={{ fontSize: 8, paddingBottom: 0 }} />
103	              }
104	              labels={({ datum }) => `${datum.name} ${datum.y} ${maxUnit}`}
105	            />
106	          }
107	          minDomain={{ y: 0 }}
108	          maxDomain={{ y: maxVal + Math.round(maxVal * 0.25) }}
109	          domainPadding={{ x: [padding, padding] }}
110	          legendComponent={
111	            <ChartLegend
112	              themeColor={ChartThemeColor.purple}
113	              data={legendData}
114	              orientation="horizontal"
115	              symbolSpacer={5}
116	              gutter={2}
117	              height={30}
118	              padding={{ top: 50, bottom: 0 }}
119	              style={{ labels: { fontSize: 8 } }}
120	            />
121	          }
122	          legendPosition="bottom-left"
123	          padding={{
124	            bottom: 50,
125	            left: 30,
126	            right: 20,
127	            top: 30,
128	          }}
129	          themeColor={ChartThemeColor.purple}
130	        >
131	          <ChartAxis style={{ tickLabels: { fontSize: 8, padding: 2 } }} />
132	          <ChartAxis
133	            dependentAxis
134	            showGrid
135	            tickCount={10}
136	            style={{
137	              tickLabels: { fontSize: 8, padding: 0 },
138	            }}
139	          />
140	          <ChartGroup offset={metric === Metrics.EGRESS ? 0 : 11}>
141	            {chartData.map((data, i) => (
142	              <ChartBar key={`chartbar-${i}`} data={data} /> // eslint-disable-line react/no-array-index-key
143	            ))}
144	          </ChartGroup>
145	        </Chart>
146	      </>
147	    );
148	  }
149	  return (
150	    <>
151	      <div className="skeleton-text nb-data-consumption-card__chart-skeleton" />
152	      <GraphEmpty height={200} loading />
153	      <div className="skeleton-text nb-data-consumption-card__chart-legend-skeleton" />
154	    </>
155	  );
156	};
157	
158	export default DataConsumptionGraph;

